3	import * as Popover from "@radix-ui/react-popover";
4	import { Input } from "@repo/ui/components/ui/input";
5	import { cn } from "@repo/ui/lib/utils";
6	import {
7	  AlignLeft,
8	  FileText,
9	  Hash,
10	  Loader2,
11	  Search as SearchIcon,
12	} from "lucide-react";
13	import type { Route } from "next";
14	import { useRouter } from "next/navigation";
15	import { useCallback, useEffect, useReducer, useRef, useState } from "react";
16	import { createPortal } from "react-dom";
17	import { useDocsSearch } from "~/app/(app)/(content)/docs/_hooks/use-docs-search";
18	import { ContentLink } from "~/components/content-link";
19	
20	type SearchAction =
21	  | { type: "OPEN" }
22	  | { type: "CLOSE" }
23	  | { type: "SELECT"; index: number }
24	  | { type: "NAVIGATE_DOWN"; max: number }
25	  | { type: "NAVIGATE_UP"; max: number };
26	
27	function searchReducer(
28	  state: { selectedIndex: number; open: boolean },
29	  action: SearchAction
30	) {
31	  switch (action.type) {
32	    case "OPEN":
33	      return { ...state, open: true };
34	    case "CLOSE":
35	      return { selectedIndex: 0, open: false };
36	    case "SELECT":
37	      return { ...state, selectedIndex: action.index };
38	    case "NAVIGATE_DOWN":
39	      if (action.max === 0) {
40	        return state;
41	      }
42	      return {
43	        ...state,
44	        selectedIndex: (state.selectedIndex + 1) % action.max,
45	      };
46	    case "NAVIGATE_UP":
47	      if (action.max === 0) {
48	        return state;
49	      }
50	      return {
51	        ...state,
52	        selectedIndex: (state.selectedIndex - 1 + action.max) % action.max,
53	      };
54	
55	    default:
56	      return state;
57	  }
58	}
59	
60	export function Search() {
61	  const [{ selectedIndex, open }, dispatch] = useReducer(searchReducer, {
62	    selectedIndex: 0,
63	    open: false,
64	  });
65	
66	  const { search, setSearch, clearSearch, results, isLoading, error } =
67	    useDocsSearch();
68	
69	  const router = useRouter();
70	  const inputRef = useRef<HTMLInputElement>(null);
71	
72	  const resultsList = results === "empty" ? [] : results;
73	
74	  const [prevResults, setPrevResults] = useState(results);
75	  if (prevResults !== results) {
76	    setPrevResults(results);
77	    dispatch({ type: "SELECT", index: 0 });
78	  }
79	
80	  const handleClose = useCallback(() => {
81	    dispatch({ type: "CLOSE" });
82	    clearSearch();
83	  }, [clearSearch]);
84	
85	  // Auto-focus input after it becomes visible (needed for mobile: input is
86	  // display:none until open, so focus() in the keydown handler is a no-op)
87	  useEffect(() => {
88	    if (open) {
89	      requestAnimationFrame(() => inputRef.current?.focus());
90	    }
91	  }, [open]);
92	
93	  useEffect(() => {
94	    function handleKeyDown(e: KeyboardEvent) {
95	      if (e.isComposing) {
96	        return;
97	      }
98	      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
99	        e.preventDefault();
100	        inputRef.current?.focus();
101	        dispatch({ type: "OPEN" });
102	      }
103	    }
104	
105	    document.addEventListener("keydown", handleKeyDown, true);
106	    return () => document.removeEventListener("keydown", handleKeyDown, true);
107	  }, []);
108	
109	  useEffect(() => {
110	    if (!open && search) {
111	      clearSearch();
112	    }
113	  }, [open, search, clearSearch]);
114	
115	  const showResults =
116	    open && (resultsList.length > 0 || search.trim().length > 0 || error);
117	
118	  return (
119	    <>
120	      {/* Overlay - renders immediately on focus */}
121	      {open &&
122	        createPortal(
123	          <div
124	            aria-hidden="true"
125	            className="fade-in-0 fixed inset-0 z-40 animate-in bg-black/20 backdrop-blur-md"
126	            onClick={() => handleClose()}
127	          />,
128	          document.body
129	        )}
130	
131	      <Popover.Root
132	        onOpenChange={(newOpen) => {
133	          if (newOpen) {
134	            dispatch({ type: "OPEN" });
135	          } else {
136	            handleClose();
137	            inputRef.current?.blur();
138	          }
139	        }}
140	        open={open}
141	      >
142	        <Popover.Anchor asChild>
143	          <div className={cn("relative", open && "z-50")}>
144	            {/* Input hidden on mobile until open, always visible on desktop */}
145	            <div
146	              className={cn(
147	                "relative items-center",
148	                open ? "flex" : "hidden lg:flex"
149	              )}
150	            >
151	              <SearchIcon className="pointer-events-none absolute left-3 z-10 h-4 w-4 text-foreground/60" />
152	              <Input
153	                className={cn(
154	                  "h-9 w-[420px] max-w-[calc(100vw-2rem)] pr-20 pl-10",
155	                  "rounded-md border border-border/50 transition-all",
156	                  "backdrop-blur-md dark:bg-card/40",
157	                  "text-foreground/60",
158	                  "focus-visible:ring-0 focus-visible:ring-offset-0",
159	                  "focus:outline-none focus-visible:outline-none",
160	                  "focus-visible:border-border/50"
161	                )}
162	                onChange={(e) => setSearch(e.target.value)}
163	                onFocus={() => dispatch({ type: "OPEN" })}
164	                onKeyDown={(e) => {
165	                  if (e.key === "Escape" && open) {
166	                    e.preventDefault();
167	                    e.stopPropagation();
168	                    handleClose();
169	                    inputRef.current?.blur();
170	                    return;
171	                  }
172	                  if (open && resultsList.length > 0) {
173	                    if (e.key === "ArrowDown") {
174	                      e.preventDefault();
175	                      dispatch({
176	                        type: "NAVIGATE_DOWN",
177	                        max: resultsList.length,
178	                      });
179	                    } else if (e.key === "ArrowUp") {
180	                      e.preventDefault();
181	                      dispatch({
182	                        type: "NAVIGATE_UP",
183	                        max: resultsList.length,
184	                      });
185	                    } else if (
186	                      e.key === "Enter" &&
187	                      resultsList[selectedIndex]
188	                    ) {
189	                      e.preventDefault();
190	                      router.push(resultsList[selectedIndex].url as Route);
191	                      handleClose();
192	                    }
193	                  }
194	                }}
195	                placeholder="Search documentation"
196	                ref={inputRef}
197	                type="text"
198	                value={search}
199	              />
200	              <div className="pointer-events-none absolute right-2 flex items-center gap-1.5">
201	                {isLoading ? (
202	                  <Loader2 className="h-4 w-4 animate-spin text-foreground/60" />
203	                ) : (
204	                  <kbd className="hidden items-center gap-1.5 rounded-md border border-border px-1.5 py-0.5 font-medium text-foreground/60 text-sm sm:inline-flex">
205	                    {open ? "ESC" : "⌘K"}
206	                  </kbd>
207	                )}
208	              </div>
209	            </div>
210	          </div>
211	        </Popover.Anchor>
212	
213	        {showResults && (
214	          <Popover.Portal>
215	            <Popover.Content
216	              align="start"
217	              alignOffset={0}
218	              className={cn(
219	                "z-50",
220	                "bg-card/40 backdrop-blur-md",
221	                "rounded-sm border border-border/50 shadow",
222	                "max-h-[420px] overflow-y-auto",
223	                "data-[state=closed]:animate-out data-[state=open]:animate-in",
224	                "data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0",
225	                "data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95"
226	              )}
227	              onEscapeKeyDown={(e) => e.preventDefault()}
228	              onInteractOutside={(e) => e.preventDefault()}
229	              onOpenAutoFocus={(e) => e.preventDefault()}
230	              side="bottom"
231	              sideOffset={6}
232	              style={{ width: "var(--radix-popover-trigger-width)" }}
233	            >
234	              {error && (
235	                <div className="px-4 py-3 text-muted-foreground/70 text-sm">
236	                  Unable to search at this time
237	                </div>
238	              )}
239	
240	              {!error && resultsList.length === 0 && (
241	                <div className="flex items-center gap-2 px-4 py-3 text-muted-foreground/70 text-sm">
242	                  <Loader2 className="h-3.5 w-3.5 animate-spin" />
243	                  Searching...
244	                </div>
245	              )}
246	
247	              {!error && resultsList.length > 0 && (
248	                <div className="">
249	                  {resultsList.map((result, index) => (
250	                    <ContentLink
251	                      className={cn(
252	                        "flex w-full items-start gap-3 px-4 py-2.5 text-left transition-colors",
253	                        "hover:bg-muted/40",
254	                        index === selectedIndex && "bg-muted/60",
255	                        result.type === "heading" && "pl-7"
256	                      )}
257	                      href={result.url}
258	                      key={result.id}
259	                      onClick={() => handleClose()}
260	                      onMouseEnter={() => dispatch({ type: "SELECT", index })}
261	                    >
262	                      <span className="mt-0.5 shrink-0 text-muted-foreground/50">
263	                        {result.type === "page" && (
264	                          <FileText className="h-4 w-4" />
265	                        )}
266	                        {result.type === "heading" && (
267	                          <Hash className="h-3.5 w-3.5" />
268	                        )}
269	                        {result.type === "text" && (
270	                          <AlignLeft className="h-3.5 w-3.5" />
271	                        )}
272	                      </span>
273	                      <div className="min-w-0">
274	                        <div
275	                          className={cn(
276	                            "truncate text-foreground text-sm",
277	                            result.type === "page" && "font-medium",
278	                            result.type !== "page" && "font-normal"
279	                          )}
280	                        >
281	                          {result.content}
282	                        </div>
283	                        {result.type === "page" && result.snippet && (
284	                          <div className="mt-0.5 line-clamp-2 text-muted-foreground/60 text-xs">
285	                            {result.snippet}
286	                          </div>
287	                        )}
288	                        {result.type === "page" &&
289	                          !result.snippet &&
290	                          result.source && (
291	                            <div className="mt-0.5 text-muted-foreground/60 text-xs">
292	                              {result.source}
293	                            </div>
294	                          )}
295	                      </div>
296	                    </ContentLink>
297	                  ))}
298	                </div>
299	              )}
300	            </Popover.Content>
301	          </Popover.Portal>
302	        )}
303	      </Popover.Root>
304	    </>
305	  );
306	}
